// Filter incoming pitch-query emails for niche relevance.
// HARO-style emails contain dozens of unrelated queries; we only care about
// the ones that match our niche so we don't waste user time.

const NICHE_KEYWORDS = [
  // Tarot
  'tarot', 'oracle card', 'card reading', 'major arcana', 'minor arcana',
  // Astrology
  'astrology', 'horoscope', 'zodiac', 'natal chart', 'birth chart',
  'mercury retrograde', 'full moon', 'new moon', 'lunar', 'solar return',
  // Other systems
  'bazi', 'four pillars', 'human design', 'i ching', 'i-ching', 'iching',
  'feng shui', 'numerology', 'angel number', 'life path',
  // Spirituality + wellness adjacent
  'spirituality', 'spiritual', 'manifestation', 'manifest', 'meditation',
  'mindfulness', 'crystal', 'crystals', 'chakra', 'aura', 'energy work',
  'witch', 'witchcraft', 'wicca', 'pagan', 'metaphysical',
  // Pop-culture intent
  'mercury in', 'venus in', 'saturn return', 'rising sign', 'sun sign',
  'moon sign', 'star sign', 'astrologer', 'tarot reader', 'psychic',
  'dream interpretation', 'dream meaning', 'lucid dream'
];

const items = $input.all();
const matches = [];

for (const item of items) {
  const subject = (item.json.subject || '').toLowerCase();
  const body = (item.json.text || item.json.snippet || '').toLowerCase();
  const haystack = `${subject}\n${body}`;

  // Find which niche keyword(s) matched and capture the surrounding context.
  const hits = [];
  for (const kw of NICHE_KEYWORDS) {
    const idx = haystack.indexOf(kw);
    if (idx >= 0) {
      const start = Math.max(0, idx - 80);
      const end = Math.min(haystack.length, idx + kw.length + 240);
      hits.push({ keyword: kw, snippet: haystack.slice(start, end).replace(/\s+/g, ' ').trim() });
    }
  }

  if (hits.length === 0) continue;

  // Try to extract a deadline if HARO/Qwoted-style format
  const deadlineMatch = body.match(/deadline[:\s]+([^\n]{1,80})/i);
  const queryMatch = body.match(/(query|topic|looking for|need)[:\s]+([^\n]{1,180})/i);

  matches.push({
    json: {
      subject: item.json.subject,
      from: item.json.from,
      date: item.json.date,
      gmailLink: `https://mail.google.com/mail/u/0/#inbox/${item.json.id}`,
      matchedKeywords: hits.slice(0, 3).map(h => h.keyword),
      previewSnippet: hits[0].snippet,
      detectedDeadline: deadlineMatch ? deadlineMatch[1].trim() : null,
      detectedQuery: queryMatch ? queryMatch[2].trim() : null
    }
  });
}

return matches;

// Build a single digest email body. If no matches, send a quiet 'nothing today' note (not spam).

const matches = $input.all();
const todayIso = new Date().toISOString().slice(0, 10);

if (matches.length === 0) {
  return [{
    json: {
      to: 'lawrence.ma000@gmail.com',
      subject: `Backlink pitch digest — ${todayIso} — no relevant queries`,
      bodyText: 'No tarot/astrology/spirituality journalist queries landed in your inbox in the last 24 hours.\n\nThis is normal — HARO shut down in 2024 and the replacements (Qwoted, SourceBottle, Help-a-B2B-Writer, Featured.com) have lower volume in this niche. Average yield is 2-3 relevant queries per week.\n\nIf you haven\'t signed up to a service yet, today is a good day:\n  - Qwoted: https://qwoted.com (free tier, weekly digest)\n  - SourceBottle: https://www.sourcebottle.com (free)\n  - Help a B2B Writer: https://helpab2bwriter.com (free)\n  - Featured.com: https://featured.com (limited free)',
      htmlBody: ''
    }
  }];
}

const sortedByDeadline = matches.sort((a, b) => {
  if (a.json.detectedDeadline && !b.json.detectedDeadline) return -1;
  if (!a.json.detectedDeadline && b.json.detectedDeadline) return 1;
  return 0;
});

const itemsHtml = sortedByDeadline.map((m, i) => {
  const j = m.json;
  return `
  <li style="margin-bottom: 18px; padding-bottom: 18px; border-bottom: 1px solid #2a2a3e;">
    <p style="margin: 0 0 4px; color: #d4af37; font-size: 13px;">
      <strong>#${i + 1}</strong>
      ${j.detectedDeadline ? `&nbsp;⏰ deadline: <span style="color: #ff6b9d;">${j.detectedDeadline}</span>` : ''}
      &nbsp;•&nbsp; matched: ${j.matchedKeywords.join(', ')}
    </p>
    <p style="margin: 0 0 6px; font-size: 14px; color: #e9e8ec;"><strong>${j.subject || '(no subject)'}</strong></p>
    ${j.detectedQuery ? `<p style="margin: 0 0 6px; color: #b8b6c4; font-size: 13px;"><em>${j.detectedQuery}</em></p>` : ''}
    <p style="margin: 0 0 6px; color: #98969f; font-size: 12px; line-height: 1.5;">${j.previewSnippet}</p>
    <p style="margin: 0; font-size: 12px;"><a href="${j.gmailLink}" style="color: #4a90e2;">Open in Gmail →</a></p>
  </li>`;
}).join('');

const bodyText = sortedByDeadline.map((m, i) => {
  const j = m.json;
  return `${i + 1}. ${j.subject}\n   matched: ${j.matchedKeywords.join(', ')}\n   ${j.detectedDeadline ? 'deadline: ' + j.detectedDeadline + '\n   ' : ''}${j.previewSnippet}\n   ${j.gmailLink}`;
}).join('\n\n');

return [{
  json: {
    to: 'lawrence.ma000@gmail.com',
    subject: `Backlink pitch digest — ${todayIso} — ${matches.length} pitchable queries`,
    bodyText: `${matches.length} journalist queries match your niche.\n\nReply ASAP — most expire within 24-48h. Backlinks from media coverage are some of the highest DR you can earn for tarotlife.app.\n\n${bodyText}\n\n---\n\nGenerated by n8n at ${new Date().toISOString()}.`,
    htmlBody: `<div style="font-family: ui-sans-serif, system-ui, sans-serif; max-width: 640px; margin: 0 auto; padding: 24px; background: #0a0a14; color: #e9e8ec;">
      <h2 style="margin: 0 0 8px; color: #d4af37; font-family: serif;">Backlink pitch digest</h2>
      <p style="margin: 0 0 18px; color: #98969f; font-size: 13px;">${todayIso} • ${matches.length} pitchable ${matches.length === 1 ? 'query' : 'queries'}</p>
      <ol style="padding: 0; list-style: none;">${itemsHtml}</ol>
      <p style="margin-top: 24px; color: #98969f; font-size: 12px; border-top: 1px solid #2a2a3e; padding-top: 16px;">Reply ASAP — pitches typically expire within 24-48h.<br/>tarotlife.app SEO automation</p>
    </div>`
  }
}];
